import hashlib
import hmac
import time

class TOTPAuthenticator:
    def __init__(self, secret):
        self.secret = secret

    def generate_totp(self, timestamp=None):
        if timestamp is None:
            timestamp = int(time.time())
        return hmac.new(self.secret, str(timestamp).encode('utf-8'), hashlib.sha1).hexdigest()[:6]

    def validate_totp(self, code):
        expected_code = self.generate_totp()
        if code == expected_code:
            return True
        else:
            return False